'use client';

/**
 * Co-pilot panel header.
 *
 * Layout (left → right):
 *   [← back]  ✨ Forge Co-pilot              [+]  [×]
 *
 * - **Back arrow** appears only when a conversation is active and
 *   takes the user back to the conversation list (clears the active
 *   conversation id without starting a new one — distinct from "+").
 * - **"+" new conversation** clears the active id AND the draft.
 * - **"×" close** uses `SheetPrimitive.Close` so the click is
 *   handled by Radix (focus return, animation, ESC consistency)
 *   and we don't accidentally double-dispatch state setters.
 */

import * as React from 'react';
import { ArrowLeft, Plus, X } from 'lucide-react';

import { Button } from '@/components/ui/button';
import { SheetClose } from '@/components/ui/sheet';
import { useCopilotStore } from '@/lib/store/copilot';

export function CopilotHeader() {
  const setActiveConversation = useCopilotStore((s) => s.setActiveConversation);
  const clearDraft = useCopilotStore((s) => s.clearDraft);
  const activeConversationId = useCopilotStore((s) => s.activeConversationId);

  // Back button is only meaningful when inside a conversation. When
  // the list / empty state is showing, the back arrow is hidden so
  // the user doesn't wonder why nothing happens.
  const showBack = activeConversationId !== null;

  const handleBack = React.useCallback(() => {
    setActiveConversation(null);
    // Intentionally DO NOT clearDraft — the user's typed message
    // should survive a back-navigation. Distinct from "+ new".
  }, [setActiveConversation]);

  const handleNew = React.useCallback(() => {
    setActiveConversation(null);
    clearDraft();
  }, [setActiveConversation, clearDraft]);

  return (
    <div className="flex items-center justify-between gap-2 border-b px-3 py-3">
      <div className="flex min-w-0 items-center gap-2">
        {showBack ? (
          <Button
            type="button"
            variant="ghost"
            size="icon"
            className="h-7 w-7 shrink-0"
            onClick={handleBack}
            aria-label="Back to conversations"
            title="Back to conversations"
            data-testid="copilot-back"
          >
            <ArrowLeft className="h-4 w-4" aria-hidden="true" />
          </Button>
        ) : null}
        <div className="flex min-w-0 items-center gap-2 text-sm font-semibold">
          <span aria-hidden="true">✨</span>
          <span className="truncate">Forge Co-pilot</span>
        </div>
      </div>
      <div className="flex shrink-0 items-center gap-1">
        <Button
          type="button"
          variant="ghost"
          size="sm"
          className="h-7 gap-1 px-2"
          onClick={handleNew}
          aria-label="New conversation"
          title="New conversation"
          data-testid="copilot-new-conversation"
        >
          <Plus className="h-3.5 w-3.5" aria-hidden="true" />
          <span className="sr-only">New conversation</span>
        </Button>
        {/* Use Radix's Close primitive so ESC + click + focus return
            all behave consistently. Avoids the duplicate "X" issue
            where the Sheet's built-in close button and this one
            both intercepted clicks at the top-right corner. */}
        <SheetClose asChild>
          <Button
            type="button"
            variant="ghost"
            size="icon"
            className="h-7 w-7"
            aria-label="Close Co-pilot"
            title="Close Co-pilot"
            data-testid="copilot-close"
          >
            <X className="h-4 w-4" aria-hidden="true" />
          </Button>
        </SheetClose>
      </div>
    </div>
  );
}
